DROP TABLE IF EXISTS `events`;
CREATE TABLE `events` (
  `sno` int NOT NULL AUTO_INCREMENT,
  `username` varchar(255) DEFAULT NULL,
  `course_prefix` varchar(255) NOT NULL,
  `course_code` int NOT NULL,
  `section` varchar(20) NOT NULL,
  `start_time` time NOT NULL,
  `end_time` time NOT NULL,
  `course_mode` varchar(20) NOT NULL,
  `days_of_week` varchar(100) NOT NULL,
  `course_name` varchar(255) NOT NULL,
  PRIMARY KEY (`sno`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

LOCK TABLES `events` WRITE;
UNLOCK TABLES;


DROP TABLE IF EXISTS `group_messages`;

CREATE TABLE `group_messages` (
  `id` int NOT NULL AUTO_INCREMENT,
  `sender` varchar(255) NOT NULL,
  `group_name` varchar(255) NOT NULL,
  `message` text NOT NULL,
  `files` json DEFAULT NULL,
  `timestamp` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;



LOCK TABLES `group_messages` WRITE;

UNLOCK TABLES;



DROP TABLE IF EXISTS `groups`;

CREATE TABLE `groups` (
  `sno` int NOT NULL AUTO_INCREMENT,
  `course_name` varchar(255) DEFAULT NULL,
  `section` varchar(50) DEFAULT NULL,
  `participants` varchar(5000) DEFAULT NULL,
  PRIMARY KEY (`sno`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


LOCK TABLES `groups` WRITE;

UNLOCK TABLES;



DROP TABLE IF EXISTS `meetings`;

CREATE TABLE `meetings` (
  `sno` int NOT NULL AUTO_INCREMENT,
  `username` varchar(255) DEFAULT NULL,
  `meeting_name` varchar(255) DEFAULT NULL,
  `date` date DEFAULT NULL,
  `start_time` time DEFAULT NULL,
  `end_time` time DEFAULT NULL,
  `meeting_mode` varchar(50) DEFAULT NULL,
  `invitees` varchar(5000) DEFAULT NULL,
  PRIMARY KEY (`sno`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

LOCK TABLES `meetings` WRITE;
UNLOCK TABLES;


DROP TABLE IF EXISTS `messages`;
CREATE TABLE `messages` (
  `id` int NOT NULL AUTO_INCREMENT,
  `sender` varchar(255) DEFAULT NULL,
  `receiver` varchar(255) DEFAULT NULL,
  `message` text,
  `files` json DEFAULT NULL,
  `timestamp` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

LOCK TABLES `messages` WRITE;
UNLOCK TABLES;


DROP TABLE IF EXISTS `notifications`;
CREATE TABLE `notifications` (
  `sno` int NOT NULL AUTO_INCREMENT,
  `sender` varchar(255) DEFAULT NULL,
  `receiver` varchar(5000) DEFAULT NULL,
  `content` text,
  `component` varchar(255) DEFAULT NULL,
  `timestamp` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`sno`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

LOCK TABLES `notifications` WRITE;
UNLOCK TABLES;


DROP TABLE IF EXISTS `users`;
CREATE TABLE `users` (
  `id` int NOT NULL AUTO_INCREMENT,
  `firstname` varchar(255) DEFAULT NULL,
  `lastname` varchar(255) DEFAULT NULL,
  `username` varchar(255) DEFAULT NULL,
  `email` varchar(255) DEFAULT NULL,
  `password` varchar(255) DEFAULT NULL,
  `privacy` varchar(10) DEFAULT NULL,
  `friends` varchar(5000) DEFAULT NULL,
  `request` varchar(5000) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

LOCK TABLES `users` WRITE;

